304	/**
305	 * FED-03: structured monitor-source pointer used by Copy/Monitor.
306	 *
307	 * `linkId` (when set) names a `link_model` element in the host whose source
308	 * model contains the monitored element; intra-host monitors omit it.
309	 * `elementId` is the **source-side** id (not the `<linkId>::<sourceElemId>`
310	 * prefixed form). `sourceRevisionAtCopy` is the source model's revision
311	 * counter at the moment of the copy; the BumpMonitoredRevisions command
312	 * compares it against the latest revision and flags drift.
313	 *
314	 * `drifted` and `driftedFields` are computed by BumpMonitoredRevisions; they
315	 * persist on the host element so the constraint evaluator can emit a
316	 * `monitored_source_drift` advisory without needing live source access.
317	 */
318	export type MonitorSource = {
319	  linkId?: string | null;
320	  elementId: string;
321	  sourceRevisionAtCopy: number;
322	  drifted?: boolean;
323	  driftedFields?: string[];
324	};
