  --draft-hidden: #757a87;
  --draft-selection: var(--color-accent);
  --draft-hover: #2c4a78;
  --draft-snap: #f3b03d;

  /* §9.3 Color — element categories, dark */
  --cat-wall: #7a7d83;
  --cat-floor: #6b5f4f;
  --cat-roof: #944f4f;
  --cat-door: #b48a64;
  --cat-window: #5482b3;
  --cat-stair: #adafb5;
  --cat-railing: #b8babf;
  --cat-room: #2e4439;
  --cat-site: #353d2e;
  --cat-section: #f15252;
  --cat-sheet: #4a4d52;
}

