/* BIM AI design tokens — drafting palette.
 *
 * Source of truth: spec/ui-ux-redesign-v1-spec.md §9.2 / §9.3 / §9.10 / §26.
 *
 * Usage rule: these tokens are CANVAS-ONLY. They MUST NOT be applied to
 * chrome elements (rails, top bar, status bar, dialogs). Chrome reads from
 * tokens-default.css / tokens-dark.css. Drafting tokens drive 2D plan canvas
 * symbology (`packages/web/src/plan/symbology/*`) and 3D viewport materials.
 */

:root,
:root[data-theme='light'] {
  /* §9.2 Color — drafting (canvas only), light. Hex literals (not modern
   * `hsl(h s% l%)` syntax) so Three.js's Color.set() parses every value
   * correctly across browsers. */
  --draft-paper: #fdfcf9;
  --draft-grid-major: #d8dcde;
  --draft-grid-minor: #ecedef;
  --draft-construction-blue: #2f7fd1;
  --draft-witness: #5a7da3;
  --draft-cut: #1d2330;
  --draft-projection: #5a6173;
  --draft-hidden: #9098a4;
  --draft-selection: var(--color-accent);
  --draft-hover: #79b1f1;
  --draft-snap: #f59e0b;

  /* §9.3 Color — element categories (3D + plan fill), light */
  --cat-wall: #969aa1;
  --cat-floor: #c2b6a3;
  --cat-roof: #7a4949;
  --cat-door: #957155;
  --cat-window: #9bbbe0;
  --cat-stair: #54585f;
  --cat-railing: #43464d;
  --cat-room: #c9dfd2;
  --cat-site: #cbd1bd;
  --cat-section: #d93d3d;
  --cat-sheet: #c9cbcf;

  /* §9.10 Drafting line weights at 1:50 plot scale (in px) */
  --draft-lw-cut-major: 2px;
  --draft-lw-cut-minor: 1.4px;
  --draft-lw-projection-major: 1px;
  --draft-lw-projection-minor: 0.7px;
  --draft-lw-hidden: 0.7px;
  --draft-lw-witness: 0.5px;
  --draft-lw-construction: 0.5px;
  /* EDT-V3-11 phase-filter lens aliases */
  --draft-lw-cut: var(--draft-lw-cut-major);
  --draft-lw-projection: var(--draft-lw-projection-major);

  /* EDT-V3-11 phase render colours */
  --phase-existing: hsl(0 0% 60%);
  --phase-demolition: hsl(0 0% 55%);
  --phase-new: hsl(0 0% 10%);
}

:root[data-theme='dark'],
:root.dark {
  /* §9.2 Color — drafting (canvas only), dark. Hex literals (see light
   * note above). */
  --draft-paper: #1a1d24;
  --draft-grid-major: #383d47;
  --draft-grid-minor: #292d35;
  --draft-construction-blue: #4ea2f7;
  --draft-witness: #8aa8c9;
