import type { JSX } from 'react';

import type { PhaseFilter } from '@bim-ai/core';

export type PhaseDropdownProps = {
  value: PhaseFilter;
  onChange: (value: PhaseFilter) => void;
};

type Option = { value: PhaseFilter; label: string; glyph: string };

const OPTIONS: readonly Option[] = [
  { value: 'all', label: 'Show All', glyph: '…' },
  { value: 'existing', label: 'Existing', glyph: '■' },
  { value: 'demolition', label: 'Demolition', glyph: '⊠' },
  { value: 'new', label: 'New Construction', glyph: '◼' },
];

/**
 * EDT-V3-11 — phase-filter lens dropdown for the plan view header chrome.
 *
 * Presentational only — the parent owns the state. Calls `onChange` with
 * the selected filter value. The same component shell is reused verbatim
 * for Design Option A/B/Main switching (KRN-V3-04).
 */
export function PhaseDropdown({ value, onChange }: PhaseDropdownProps): JSX.Element {
  const active = OPTIONS.find((o) => o.value === value) ?? OPTIONS[0];

  return (
    <div className="relative inline-block">
      <select
        data-testid="phase-dropdown"
        aria-label="Phase filter"
        value={value}
        onChange={(e) => onChange(e.target.value as PhaseFilter)}
        className="appearance-none rounded border border-border bg-background px-2 py-1 pr-6 text-[11px] text-foreground hover:bg-muted/10"
      >
        {OPTIONS.map((o) => (
          <option key={o.value} value={o.value}>
            {o.glyph} {o.label}
          </option>
        ))}
      </select>
      <span
        aria-hidden
        className="pointer-events-none absolute right-1.5 top-1/2 -translate-y-1/2 text-[9px] text-muted"
      >
        {active.glyph}
      </span>
    </div>
  );
}

